// Helper: get country info by ISO numeric id
window.SkyHigh.getWorldCountry = function(numericId) {
  const id = parseInt(numericId);
  return SkyHigh.WORLD_COUNTRIES[id] || { name: `Country #${id}`, region: 'Unknown', risk: 'MEDIUM', tier: 'MEDIUM', emoji: '🌍' };
};

