// ── GEO UTILITIES ─────────────────────────────────────────
window.SkyHigh.GeoUtils = {
  distance(lat1, lon1, lat2, lon2) {
    const R = 6371;
    const dLat = (lat2-lat1)*Math.PI/180;
    const dLon = (lon2-lon1)*Math.PI/180;
    const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
    return R*2*Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  },
  getDistanceBand(km) {
    const b = SkyHigh.MAP_DATA.distanceBands;
    if (km<=b.SHORT.maxKm) return 'SHORT';
    if (km<=b.MEDIUM.maxKm) return 'MEDIUM';
    if (km<=b.LONG.maxKm) return 'LONG';
    return 'ULTRA';
  },
  getAirport(id) { return SkyHigh.MAP_DATA.airports.find(a=>a.id===id); },
  getAirportsByCountryIso(iso) { return SkyHigh.MAP_DATA.airports.filter(a=>a.countryIso===iso); },
};
